definition.script:
pipeline {
    agent any
    parameters {
        string(name: 'GIT_URL', defaultValue: 'https://github.com/Linuary/paperclip.git')
        choice(name: 'BRANCH', choices: ['dev-custom', 'main', 'master'])
        string(name: 'TARGET_HOST', defaultValue: '47.236.51.128')
    }
    stages {
        stage('Build') {
            steps {
                sh "echo Building..."
            }
        }
    }
}
